# Generated by Claude on 2026-05-13 for task 01. Prompt: thesis_prompts/01_static_pick_place.md
# Fixed version of 01_static_pick_place_controller.py:
#   - uses interface_config_loader's dedicated "FR3" RMPflow preset
#     (instead of "Franka", whose joint names don't match the FR3);
#   - reads EE world position from fr3_hand_tcp (matches RMPflow gripper_center)
#     instead of fr3_hand, so convergence tolerance is meaningful.
# This is the version that produced the verified success.
"""
FR3 pick-and-place controller driven by an OmniGraph ScriptNode (OnPlaybackTick).

Coordinates here came from get_prim_info on the live stage; they are not
hand-authored magic numbers. See the constants block below.
"""

import numpy as np
from pxr import UsdGeom, UsdPhysics, Usd

# --- Queried scene constants (from get_prim_info, do not hardcode by hand) ---
# Table 1: center=(0.5, -0.35, 0.2), size=(0.3, 0.2, 0.4)  -> top z = 0.4
# Table 2: center=(0.5,  0.35, 0.2), size=(0.3, 0.2, 0.4)  -> top z = 0.4
# Cube   : center=(0.5, -0.35, 0.425), size=(0.05, 0.05, 0.05)
TABLE1_CENTER = np.array([0.5, -0.35, 0.2])
TABLE1_SIZE   = np.array([0.3, 0.2, 0.4])
TABLE2_CENTER = np.array([0.5,  0.35, 0.2])
TABLE2_SIZE   = np.array([0.3, 0.2, 0.4])
CUBE_INIT     = np.array([0.5, -0.35, 0.425])
CUBE_SIZE     = 0.05

TABLE1_TOP_Z = TABLE1_CENTER[2] + TABLE1_SIZE[2] / 2.0
TABLE2_TOP_Z = TABLE2_CENTER[2] + TABLE2_SIZE[2] / 2.0
CUBE_HALF    = CUBE_SIZE / 2.0

PICK_XYZ  = np.array([TABLE1_CENTER[0], TABLE1_CENTER[1], TABLE1_TOP_Z + CUBE_HALF])
PLACE_XYZ = np.array([TABLE2_CENTER[0], TABLE2_CENTER[1], TABLE2_TOP_Z + CUBE_HALF])

APPROACH_HEIGHT = 0.15

ROBOT_PRIM     = "/World/FrankaFR3"
CUBE_PRIM      = "/World/TargetCube"
END_EFFECTOR   = "fr3_hand_tcp"      # TCP frame (matches RMPflow gripper_center)
GRIPPER_OPEN   = 0.04
GRIPPER_CLOSED = 0.005

_STATE = {
    "initialized": False, "phase": 0, "phase_frames": 0,
    "robot": None, "rmpflow": None, "articulation_rmpflow": None,
    "gripper": None, "target_pose": None,
}

PHASES = [
    ("approach_pick",  PICK_XYZ + np.array([0, 0, APPROACH_HEIGHT]), GRIPPER_OPEN),
    ("descend_pick",   PICK_XYZ,                                      GRIPPER_OPEN),
    ("grasp",          PICK_XYZ,                                      GRIPPER_CLOSED),
    ("lift",           PICK_XYZ + np.array([0, 0, APPROACH_HEIGHT]), GRIPPER_CLOSED),
    ("approach_place", PLACE_XYZ + np.array([0, 0, APPROACH_HEIGHT]), GRIPPER_CLOSED),
    ("descend_place",  PLACE_XYZ,                                     GRIPPER_CLOSED),
    ("release",        PLACE_XYZ,                                     GRIPPER_OPEN),
    ("retreat",        PLACE_XYZ + np.array([0, 0, APPROACH_HEIGHT]), GRIPPER_OPEN),
]

PHASE_MIN_FRAMES = {"grasp": 60, "release": 30}
DEFAULT_MIN_FRAMES = 1
POS_TOL = 0.02


def _initialize():
    from isaacsim.core.prims import SingleArticulation
    from isaacsim.robot_motion.motion_generation import (
        RmpFlow, ArticulationMotionPolicy, interface_config_loader,
    )
    from isaacsim.robot.manipulators.grippers import ParallelGripper

    robot = SingleArticulation(prim_path=ROBOT_PRIM, name="fr3")
    robot.initialize()

    # Dedicated FR3 preset (separate from "Franka", which targets the older
    # Panda joint names).
    rmpflow_cfg = interface_config_loader.load_supported_motion_policy_config(
        "FR3", "RMPflow"
    )
    rmpflow = RmpFlow(**rmpflow_cfg)

    art_rmpflow = ArticulationMotionPolicy(
        robot_articulation=robot,
        motion_policy=rmpflow,
        default_physics_dt=1.0 / 60.0,
    )

    # The ParallelGripper's end_effector_prim_path is just the link the gripper
    # is attached to (used for hierarchy lookups); it does NOT have to be the TCP.
    gripper = ParallelGripper(
        end_effector_prim_path=f"{ROBOT_PRIM}/fr3_hand",
        joint_prim_names=["fr3_finger_joint1", "fr3_finger_joint2"],
        joint_opened_positions=np.array([GRIPPER_OPEN, GRIPPER_OPEN]),
        joint_closed_positions=np.array([GRIPPER_CLOSED, GRIPPER_CLOSED]),
        action_deltas=np.array([0.01, 0.01]),
    )
    gripper.initialize(
        articulation_apply_action_func=robot.apply_action,
        get_joint_positions_func=robot.get_joint_positions,
        set_joint_positions_func=robot.set_joint_positions,
        dof_names=robot.dof_names,
    )

    _STATE["robot"] = robot
    _STATE["rmpflow"] = rmpflow
    _STATE["articulation_rmpflow"] = art_rmpflow
    _STATE["gripper"] = gripper
    _STATE["initialized"] = True
    print("[pick_and_place] initialized RMPflow + ParallelGripper for FR3")


def _ee_position():
    import omni.usd
    stage = omni.usd.get_context().get_stage()
    prim = stage.GetPrimAtPath(f"{ROBOT_PRIM}/{END_EFFECTOR}")
    if not prim or not prim.IsValid():
        return None
    m = UsdGeom.Xformable(prim).ComputeLocalToWorldTransform(Usd.TimeCode.Default())
    return np.array([m[3][0], m[3][1], m[3][2]])


def _advance_phase_if_done():
    idx = _STATE["phase"]
    if idx >= len(PHASES):
        return
    name, target_xyz, _ = PHASES[idx]
    min_frames = PHASE_MIN_FRAMES.get(name, DEFAULT_MIN_FRAMES)
    if _STATE["phase_frames"] < min_frames:
        return
    ee = _ee_position()
    if ee is None:
        return
    err = np.linalg.norm(ee - target_xyz)
    if err < POS_TOL or _STATE["phase_frames"] > 240:
        print(f"[pick_and_place] phase '{name}' done (err={err:.3f}m, "
              f"frames={_STATE['phase_frames']}) -> next")
        _STATE["phase"] += 1
        _STATE["phase_frames"] = 0


def _drive_current_phase():
    idx = _STATE["phase"]
    if idx >= len(PHASES):
        return
    name, target_xyz, gripper_target = PHASES[idx]
    target_orient = np.array([0.0, 1.0, 0.0, 0.0])
    _STATE["rmpflow"].set_end_effector_target(
        target_position=target_xyz, target_orientation=target_orient,
    )
    _STATE["rmpflow"].update_world()
    action = _STATE["articulation_rmpflow"].get_next_articulation_action()
    _STATE["robot"].apply_action(action)
    finger_action = _STATE["gripper"].forward(
        action="close" if gripper_target < GRIPPER_OPEN * 0.5 else "open"
    )
    if finger_action is not None:
        _STATE["robot"].apply_action(finger_action)


def step():
    if not _STATE["initialized"]:
        try:
            _initialize()
        except Exception as e:
            print(f"[pick_and_place] init deferred: {e}")
            return
    _drive_current_phase()
    _STATE["phase_frames"] += 1
    _advance_phase_if_done()


def setup(db):
    db.log_info("[pick_and_place] ScriptNode setup")
    _STATE["initialized"] = False
    _STATE["phase"] = 0
    _STATE["phase_frames"] = 0


def compute(db):
    try:
        step()
    except Exception as e:
        db.log_error(f"[pick_and_place] step() raised: {e}")
        return False
    return True


def cleanup(db):
    db.log_info("[pick_and_place] ScriptNode cleanup")
    _STATE["initialized"] = False
    for k in ("robot", "rmpflow", "articulation_rmpflow", "gripper"):
        _STATE[k] = None
